# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
from flask import Flask, request, jsonify

app = Flask(__name__)

def get_db_connection():
    connection = pymysql.connect(
        host='your_host',
        user='your_user',
        password='your_password',
        db='your_database',
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor
    )
    return connection

@app.route('/search', methods=['GET'])
def search():
    try:
        # Extract parameters from request
        table = request.args.get('table')
        columns = request.args.getlist('columns[]')  # Assuming multiple columns can be selected
        filters = request.args.getlist('filters[]')  # Assuming multiple filters in 'column_name=value' format

        if not table or not columns:
            return jsonify({"error": "Table and columns are required"}), 400

        # Construct SQL query
        sql_query = f"SELECT {', '.join(columns)} FROM {table} WHERE 1=1"

        for filter in filters:
            key, value = filter.split('=')
            sql_query += f" AND {key}='{value}'"

        # Execute query
        connection = get_db_connection()
        with connection.cursor() as cursor:
            cursor.execute(sql_query)
            result = cursor.fetchall()

        return jsonify(result), 200

    except Exception as e:
        return jsonify({"error": str(e)}), 500
    finally:
        connection.close()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)